// Thứ tự ĐÚNG cho ASP.NET Core app
app.UseExceptionHandler("/error");      // 1. Bắt exception toàn cục
app.UseHsts();                          // 2. Security headers
app.UseHttpsRedirection();              // 3. HTTPS redirect
app.UseStaticFiles();                   // 4. Static files (short-circuit nếu tìm thấy)
app.UseRouting();                       // 5. Route matching (phải trước Auth)
app.UseCors("MyPolicy");               // 6. CORS (phải sau Routing, trước Auth)
app.UseRateLimiter();                   // 7. Rate limiting (biết endpoint qua routing)
app.UseAuthentication();               // 8. Xác thực danh tính
app.UseAuthorization();                // 9. Kiểm tra quyền (phải SAU Authentication)
app.MapControllers();                  // 10. Endpoint execution

// Custom middleware: Use vs Run vs Map
// Use: có thể gọi next
app.Use(async (ctx, next) => {
    // Before next middleware
    await next.Invoke();
    // After next middleware (response phase)
});

// Run: terminal — không gọi next
app.Run(ctx => ctx.Response.WriteAsync("Terminal"));

// Map: branch pipeline theo path
app.Map("/health", healthApp => healthApp.Run(async ctx =>
    await ctx.Response.WriteAsJsonAsync(new { status = "healthy" })));
